mapper.select:
/* com.kt.ipms.legacy.ipmgmt.ipuploadmgmt.dao.TbIpUploadDao.selectListPageIpUpload */ SELECT TT.RNUM, TT.SEQ , TT.SFILE_NM , (CASE WHEN TT.SSSUCESS_YN = 'Y' THEN '성공' ELSE '실패' END) AS SSSUCESS_YN, TT.PIP_PREFIX , TT.DCREATE_DT , TT.SCREATE_ID , TT.DMODIFY_DT , TT.SMODIFY_ID FROM ( SELECT ROWNUM AS RNUM, T.SEQ , T.SFILE_NM , T.SSSUCESS_YN , T.PIP_PREFIX , T.DCREATE_DT , T.SCREATE_ID , T.DMODIFY_DT , T.SMODIFY_ID FROM ( SELECT SEQ , SFILE_NM , SSSUCESS_YN , PIP_PREFIX , DCREATE_DT , SCREATE_ID , DMODIFY_DT , SMODIFY_ID FROM MST.TB_UPLOAD_IP WHERE 1=1
AND sssucess_yn = #{sSsucessYn, jdbcType=VARCHAR}
AND DCREATE_DT >= #{searchBgnDe, jdbcType=TIMESTAMP}
AND DCREATE_DT <= #{searchEndDe, jdbcType=TIMESTAMP}
ORDER BY DCREATE_DT DESC ) T WHERE ROWNUM <= #{lastIndex} ) TT WHERE RNUM >= #{firstIndex}

/* com.kt.ipms.legacy.ipmgmt.ipuploadmgmt.dao.TbIpUploadDao.countListPageIpUpload */
SELECT
	COUNT(1) AS totalCount
FROM 
	MST.TB_UPLOAD_IP
WHERE
1=1

		AND sssucess_yn = #{sSsucessYn, jdbcType=VARCHAR}


		AND DCREATE_DT >= #{searchBgnDe, jdbcType=TIMESTAMP}


		AND DCREATE_DT <= #{searchEndDe, jdbcType=TIMESTAMP}

/* com.kt.ipms.legacy.ipmgmt.ipuploadmgmt.dao.TbIpUploadDao.selectListTbIpHostMst */ SELECT A.SRSSOFFICESCODE AS SOFFICECODE -- 수용국코드 , A.SIP_BLOCK AS SSUBSCMSTIP -- 장비대표IP , A.SMODELNAME AS SMODELNAME -- 모델명 , A.SNESCODE AS SSUBSCNESCODE -- 시설표준코드 , A.SIP_HOST_NM AS SSUBSCNEALIAS -- 장비명 , DECODE(B.SLVL_NM ,NULL ,'',B.SLVL_NM) AS SOFFICENAME -- 수용국 FROM MST.TB_IP_HOST_MST A , MST.TB_LVL_CD B , MST.TB_IP_HOST_TYPE_CD C WHERE 1=1 AND A.SRSSOFFICESCODE = B.SLVL_CD(+) AND A.SIP_HOST_TYPE_CD = C.SIP_HOST_TYPE_CD
AND A.SRSSOFFICESCODE = #{sicisofficescodeNe, jdbcType=VARCHAR}
AND A.SRSSOFFICESCODE IN ( SELECT DISTINCT M.SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB M INNER JOIN MST.TB_LVL_MST T ON M.SSVC_LINE_TYPE_CD = T.SSVC_LINE_TYPE_CD AND M.SSVC_OBJ_CD = T.SSVC_OBJ_CD WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
)
AND A.SIP_HOST_NM ILIKE '%' || #{ssubscnealiasNe, jdbcType=VARCHAR} || '%'
AND A.SMODELNAME ILIKE '%' || #{smodelnameNe, jdbcType=VARCHAR} || '%'
AND A.SIP_BLOCK ILIKE '%' || #{ssubscmstipNe, jdbcType=VARCHAR} || '%'
AND C.SALLOC_FLAG_YN = 'Y' GROUP BY A.SRSSOFFICESCODE , B.SLVL_NM , A.SIP_HOST_NM , A.SMODELNAME , A.SIP_BLOCK , A.SNESCODE ORDER BY A.SIP_HOST_NM , A.SMODELNAME , A.SIP_BLOCK

mapper.insert:
/* com.kt.ipms.legacy.ipmgmt.ipuploadmgmt.dao.TbIpUploadDao.insertTbIpUploadMst */
INSERT INTO mst.tb_upload_ip (
	sfile_nm,
	sssucess_yn,
	dcreate_dt,
	screate_id
) VALUES (
	#{sFileNm, jdbcType=VARCHAR},
	'N',
	sysdate,
	#{screateId, jdbcType=VARCHAR}
);

	SELECT LASTVAL()

mapper.select:
/* com.kt.ipms.legacy.ipmgmt.ipuploadmgmt.dao.TbIpUploadDao.selectAssignMstSeq */
SELECT 
	nip_assign_mst_seq  
FROM 
	mst.tb_ip_assign_mst tiam 
WHERE 
	ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=VARCHAR}
	AND nlvl_mst_seq = (
		SELECT 
			nmax_seq 
		FROM 
			mst.tb_lvl_bas 
		WHERE 
			ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=VARCHAR} 
			AND ssvc_group_cd = #{ssvcGroupCd, jdbcType=VARCHAR} 
			AND ssvc_obj_cd = #{ssvcObjCd, jdbcType=VARCHAR}
	)
	AND pip_prefix = #{pipprefix, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler};

/* com.kt.ipms.legacy.ipmgmt.ipuploadmgmt.dao.TbIpUploadDao.selectNlvlMstSeq */
SELECT 
	nmax_seq AS nlvl_mst_seq 
FROM 
	mst.tb_lvl_bas 
WHERE 
	ssvc_line_type_cd = #{ssvcLineTypeCd, jdbcType=VARCHAR}
	AND ssvc_group_cd = #{ssvcGroupCd, jdbcType=VARCHAR}
	AND ssvc_obj_cd = #{ssvcObjCd, jdbcType=VARCHAR};

SELECT A.SSVC_LINE_TYPE_CD AS SSVC_LINE_TYPE_CD , A.SIP_CREATE_TYPE_CD AS SIP_CREATE_TYPE_CD , A.SASSIGN_TYPE_CD AS SASSIGN_TYPE_CD , A.PIP_PREFIX AS PIP_PREFIX , A.PIP_PREFIX_RANGE , A.SICISOFFICESCODE , A.SSUBSCMSTIP , A.SMODELNAME , A.SGATEWAYIP , A.SSUBSCNESCODE , A.SSUBSCNEALIAS , A.SLLNUM , A.SSUBSCLGIPPORTDESCRIPTION , A.SSUBSCLGIPPORTIP , A.SSUBSCROUTERSERIALIP , A.SCONNALIAS , A.SCOMMENT FROM (
SELECT A.SSVC_LINE_TYPE_CD AS SSVC_LINE_TYPE_CD , A.SIP_CREATE_TYPE_CD AS SIP_CREATE_TYPE_CD , A.SASSIGN_TYPE_CD AS SASSIGN_TYPE_CD , A.PIP_PREFIX AS PIP_PREFIX , '10.221.132.0/24' AS PIP_PREFIX_RANGE --, F.PIP_PREFIX AS PIP_PREFIX_RANGE , NVL(B.SICISOFFICESCODE,'') AS SICISOFFICESCODE , NVL(B.SSUBSCMSTIP,'') AS SSUBSCMSTIP , NVL(B.SMODELNAME,'') AS SMODELNAME , NVL(B.SGATEWAYIP, SPLIT_PART(A.SLAST_ADDR, '.', 1) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 2) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 3) || '.' || TO_NUMBER(SPLIT_PART(A.SLAST_ADDR, '.', 4)) -2) AS SGATEWAYIP , NVL(B.SSUBSCNESCODE,'') AS SSUBSCNESCODE , NVL(B.SSUBSCNEALIAS,'') AS SSUBSCNEALIAS , NVL(B.SLLNUM,'') AS SLLNUM , NVL(B.SSUBSCLGIPPORTDESCRIPTION,'') AS SSUBSCLGIPPORTDESCRIPTION , NVL(B.SSUBSCLGIPPORTIP,'') AS SSUBSCLGIPPORTIP , NVL(B.SSUBSCROUTERSERIALIP,'') AS SSUBSCROUTERSERIALIP , NVL(B.SCONNALIAS,'') AS SCONNALIAS , NVL(A.SCOMMENT, '') AS SCOMMENT FROM MST.TB_IP_ASSIGN_MST_BAK_20230220 A LEFT OUTER JOIN MST.TB_IP_ALLOC_MST_BAK_20230220 B ON B.NIP_ASSIGN_MST_SEQ = A.NIP_ASSIGN_MST_SEQ LEFT OUTER JOIN MST.TB_LVL_MST C ON C.NLVL_MST_SEQ = A.NLVL_MST_SEQ LEFT OUTER JOIN MST.TB_LVL_CD D ON D.SLVL_CD = C.SSVC_GROUP_CD LEFT OUTER JOIN MST.TB_LVL_CD E ON E.SLVL_CD = C.SSVC_OBJ_CD LEFT OUTER JOIN MST.TB_IP_BLOCK_MST_BAK_20230220 F ON F.NIP_BLOCK_MST_SEQ = A.NIP_BLOCK_MST_SEQ WHERE A.SIP_CREATE_TYPE_CD = 'CT0005' AND A.SSVC_LINE_TYPE_CD = 'CL0002' AND C.SSVC_GROUP_CD = '369819' AND C.SSVC_OBJ_CD = 'VV0096' AND A.SASSIGN_LEVEL_CD IN ('IA0006', 'IA0005') AND A.SIP_BLOCK LIKE '10.221.132.%' GROUP BY A.SSVC_LINE_TYPE_CD , A.SIP_CREATE_TYPE_CD , A.SASSIGN_TYPE_CD , A.PIP_PREFIX , F.PIP_PREFIX , NVL(B.SICISOFFICESCODE,'') , NVL(B.SSUBSCMSTIP,'') , NVL(B.SMODELNAME,'') , NVL(B.SGATEWAYIP, SPLIT_PART(A.SLAST_ADDR, '.', 1) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 2) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 3) || '.' || TO_NUMBER(SPLIT_PART(A.SLAST_ADDR, '.', 4)) -2) , NVL(B.SSUBSCNESCODE,'') , NVL(B.SSUBSCNEALIAS,'') , NVL(B.SLLNUM,'') , NVL(B.SSUBSCLGIPPORTDESCRIPTION,'') , NVL(B.SSUBSCLGIPPORTIP,'') , NVL(B.SSUBSCROUTERSERIALIP,'') , NVL(B.SCONNALIAS,'') , NVL(A.SCOMMENT, '') UNION SELECT A.SSVC_LINE_TYPE_CD AS SSVC_LINE_TYPE_CD , A.SIP_CREATE_TYPE_CD AS SIP_CREATE_TYPE_CD , A.SASSIGN_TYPE_CD AS SASSIGN_TYPE_CD , A.PIP_PREFIX AS PIP_PREFIX , '10.221.144.0/24' AS PIP_PREFIX_RANGE --, F.PIP_PREFIX AS PIP_PREFIX_RANGE , NVL(B.SICISOFFICESCODE,'') AS SICISOFFICESCODE , NVL(B.SSUBSCMSTIP,'') AS SSUBSCMSTIP , NVL(B.SMODELNAME,'') AS SMODELNAME , NVL(B.SGATEWAYIP, SPLIT_PART(A.SLAST_ADDR, '.', 1) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 2) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 3) || '.' || TO_NUMBER(SPLIT_PART(A.SLAST_ADDR, '.', 4)) -2) AS SGATEWAYIP , NVL(B.SSUBSCNESCODE,'') AS SSUBSCNESCODE , NVL(B.SSUBSCNEALIAS,'') AS SSUBSCNEALIAS , NVL(B.SLLNUM,'') AS SLLNUM , NVL(B.SSUBSCLGIPPORTDESCRIPTION,'') AS SSUBSCLGIPPORTDESCRIPTION , NVL(B.SSUBSCLGIPPORTIP,'') AS SSUBSCLGIPPORTIP , NVL(B.SSUBSCROUTERSERIALIP,'') AS SSUBSCROUTERSERIALIP , NVL(B.SCONNALIAS,'') AS SCONNALIAS , NVL(A.SCOMMENT, '') AS SCOMMENT FROM MST.TB_IP_ASSIGN_MST_BAK_20230220 A LEFT OUTER JOIN MST.TB_IP_ALLOC_MST_BAK_20230220 B ON B.NIP_ASSIGN_MST_SEQ = A.NIP_ASSIGN_MST_SEQ LEFT OUTER JOIN MST.TB_LVL_MST C ON C.NLVL_MST_SEQ = A.NLVL_MST_SEQ LEFT OUTER JOIN MST.TB_LVL_CD D ON D.SLVL_CD = C.SSVC_GROUP_CD LEFT OUTER JOIN MST.TB_LVL_CD E ON E.SLVL_CD = C.SSVC_OBJ_CD LEFT OUTER JOIN MST.TB_IP_BLOCK_MST_BAK_20230220 F ON F.NIP_BLOCK_MST_SEQ = A.NIP_BLOCK_MST_SEQ WHERE A.SIP_CREATE_TYPE_CD = 'CT0005' AND A.SSVC_LINE_TYPE_CD = 'CL0002' AND C.SSVC_GROUP_CD = '369819' AND C.SSVC_OBJ_CD = 'VV0096' AND A.SASSIGN_LEVEL_CD IN ('IA0006', 'IA0005') AND A.SIP_BLOCK LIKE '10.221.144.%' GROUP BY A.SSVC_LINE_TYPE_CD , A.SIP_CREATE_TYPE_CD , A.SASSIGN_TYPE_CD , A.PIP_PREFIX , F.PIP_PREFIX , NVL(B.SICISOFFICESCODE,'') , NVL(B.SSUBSCMSTIP,'') , NVL(B.SMODELNAME,'') , NVL(B.SGATEWAYIP, SPLIT_PART(A.SLAST_ADDR, '.', 1) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 2) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 3) || '.' || TO_NUMBER(SPLIT_PART(A.SLAST_ADDR, '.', 4)) -2) , NVL(B.SSUBSCNESCODE,'') , NVL(B.SSUBSCNEALIAS,'') , NVL(B.SLLNUM,'') , NVL(B.SSUBSCLGIPPORTDESCRIPTION,'') , NVL(B.SSUBSCLGIPPORTIP,'') , NVL(B.SSUBSCROUTERSERIALIP,'') , NVL(B.SCONNALIAS,'') , NVL(A.SCOMMENT, '') UNION SELECT A.SSVC_LINE_TYPE_CD AS SSVC_LINE_TYPE_CD , A.SIP_CREATE_TYPE_CD AS SIP_CREATE_TYPE_CD , A.SASSIGN_TYPE_CD AS SASSIGN_TYPE_CD , A.PIP_PREFIX AS PIP_PREFIX , '172.16.158.0/24' AS PIP_PREFIX_RANGE --, F.PIP_PREFIX AS PIP_PREFIX_RANGE , NVL(B.SICISOFFICESCODE,'') AS SICISOFFICESCODE , NVL(B.SSUBSCMSTIP,'') AS SSUBSCMSTIP , NVL(B.SMODELNAME,'') AS SMODELNAME , NVL(B.SGATEWAYIP, SPLIT_PART(A.SLAST_ADDR, '.', 1) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 2) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 3) || '.' || TO_NUMBER(SPLIT_PART(A.SLAST_ADDR, '.', 4)) -2) AS SGATEWAYIP , NVL(B.SSUBSCNESCODE,'') AS SSUBSCNESCODE , NVL(B.SSUBSCNEALIAS,'') AS SSUBSCNEALIAS , NVL(B.SLLNUM,'') AS SLLNUM , NVL(B.SSUBSCLGIPPORTDESCRIPTION,'') AS SSUBSCLGIPPORTDESCRIPTION , NVL(B.SSUBSCLGIPPORTIP,'') AS SSUBSCLGIPPORTIP , NVL(B.SSUBSCROUTERSERIALIP,'') AS SSUBSCROUTERSERIALIP , NVL(B.SCONNALIAS,'') AS SCONNALIAS , NVL(A.SCOMMENT, '') AS SCOMMENT FROM MST.TB_IP_ASSIGN_MST_BAK_20230220 A LEFT OUTER JOIN MST.TB_IP_ALLOC_MST_BAK_20230220 B ON B.NIP_ASSIGN_MST_SEQ = A.NIP_ASSIGN_MST_SEQ LEFT OUTER JOIN MST.TB_LVL_MST C ON C.NLVL_MST_SEQ = A.NLVL_MST_SEQ LEFT OUTER JOIN MST.TB_LVL_CD D ON D.SLVL_CD = C.SSVC_GROUP_CD LEFT OUTER JOIN MST.TB_LVL_CD E ON E.SLVL_CD = C.SSVC_OBJ_CD LEFT OUTER JOIN MST.TB_IP_BLOCK_MST_BAK_20230220 F ON F.NIP_BLOCK_MST_SEQ = A.NIP_BLOCK_MST_SEQ WHERE A.SIP_CREATE_TYPE_CD = 'CT0005' AND A.SSVC_LINE_TYPE_CD = 'CL0002' AND C.SSVC_GROUP_CD = '369819' AND C.SSVC_OBJ_CD = 'VV0096' AND A.SASSIGN_LEVEL_CD IN ('IA0006', 'IA0005') AND A.SIP_BLOCK LIKE '172.16.158.%' GROUP BY A.SSVC_LINE_TYPE_CD , A.SIP_CREATE_TYPE_CD , A.SASSIGN_TYPE_CD , A.PIP_PREFIX , F.PIP_PREFIX , NVL(B.SICISOFFICESCODE,'') , NVL(B.SSUBSCMSTIP,'') , NVL(B.SMODELNAME,'') , NVL(B.SGATEWAYIP, SPLIT_PART(A.SLAST_ADDR, '.', 1) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 2) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 3) || '.' || TO_NUMBER(SPLIT_PART(A.SLAST_ADDR, '.', 4)) -2) , NVL(B.SSUBSCNESCODE,'') , NVL(B.SSUBSCNEALIAS,'') , NVL(B.SLLNUM,'') , NVL(B.SSUBSCLGIPPORTDESCRIPTION,'') , NVL(B.SSUBSCLGIPPORTIP,'') , NVL(B.SSUBSCROUTERSERIALIP,'') , NVL(B.SCONNALIAS,'') , NVL(A.SCOMMENT, '') UNION SELECT A.SSVC_LINE_TYPE_CD AS SSVC_LINE_TYPE_CD , A.SIP_CREATE_TYPE_CD AS SIP_CREATE_TYPE_CD , A.SASSIGN_TYPE_CD AS SASSIGN_TYPE_CD , A.PIP_PREFIX AS PIP_PREFIX , '172.16.170.0/24' AS PIP_PREFIX_RANGE --, F.PIP_PREFIX AS PIP_PREFIX_RANGE , NVL(B.SICISOFFICESCODE,'') AS SICISOFFICESCODE , NVL(B.SSUBSCMSTIP,'') AS SSUBSCMSTIP , NVL(B.SMODELNAME,'') AS SMODELNAME , NVL(B.SGATEWAYIP, SPLIT_PART(A.SLAST_ADDR, '.', 1) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 2) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 3) || '.' || TO_NUMBER(SPLIT_PART(A.SLAST_ADDR, '.', 4)) -2) AS SGATEWAYIP , NVL(B.SSUBSCNESCODE,'') AS SSUBSCNESCODE , NVL(B.SSUBSCNEALIAS,'') AS SSUBSCNEALIAS , NVL(B.SLLNUM,'') AS SLLNUM , NVL(B.SSUBSCLGIPPORTDESCRIPTION,'') AS SSUBSCLGIPPORTDESCRIPTION , NVL(B.SSUBSCLGIPPORTIP,'') AS SSUBSCLGIPPORTIP , NVL(B.SSUBSCROUTERSERIALIP,'') AS SSUBSCROUTERSERIALIP , NVL(B.SCONNALIAS,'') AS SCONNALIAS , NVL(A.SCOMMENT, '') AS SCOMMENT FROM MST.TB_IP_ASSIGN_MST_BAK_20230220 A LEFT OUTER JOIN MST.TB_IP_ALLOC_MST_BAK_20230220 B ON B.NIP_ASSIGN_MST_SEQ = A.NIP_ASSIGN_MST_SEQ LEFT OUTER JOIN MST.TB_LVL_MST C ON C.NLVL_MST_SEQ = A.NLVL_MST_SEQ LEFT OUTER JOIN MST.TB_LVL_CD D ON D.SLVL_CD = C.SSVC_GROUP_CD LEFT OUTER JOIN MST.TB_LVL_CD E ON E.SLVL_CD = C.SSVC_OBJ_CD LEFT OUTER JOIN MST.TB_IP_BLOCK_MST_BAK_20230220 F ON F.NIP_BLOCK_MST_SEQ = A.NIP_BLOCK_MST_SEQ WHERE A.SIP_CREATE_TYPE_CD = 'CT0005' AND A.SSVC_LINE_TYPE_CD = 'CL0002' AND C.SSVC_GROUP_CD = '369819' AND C.SSVC_OBJ_CD