SELECT A.SSVC_LINE_TYPE_CD AS SSVC_LINE_TYPE_CD , A.SIP_CREATE_TYPE_CD AS SIP_CREATE_TYPE_CD , A.SASSIGN_TYPE_CD AS SASSIGN_TYPE_CD , A.PIP_PREFIX AS PIP_PREFIX , A.PIP_PREFIX_RANGE , A.SICISOFFICESCODE , A.SSUBSCMSTIP , A.SMODELNAME , A.SGATEWAYIP , A.SSUBSCNESCODE , A.SSUBSCNEALIAS , A.SLLNUM , A.SSUBSCLGIPPORTDESCRIPTION , A.SSUBSCLGIPPORTIP , A.SSUBSCROUTERSERIALIP , A.SCONNALIAS , A.SCOMMENT FROM ( SELECT A.SSVC_LINE_TYPE_CD AS SSVC_LINE_TYPE_CD , A.SIP_CREATE_TYPE_CD AS SIP_CREATE_TYPE_CD , A.SASSIGN_TYPE_CD AS SASSIGN_TYPE_CD , A.PIP_PREFIX AS PIP_PREFIX , CAST(C.PIP_PREFIX_RANGE AS VARCHAR) AS PIP_PREFIX_RANGE , NVL(B.SICISOFFICESCODE,'') AS SICISOFFICESCODE , NVL(B.SSUBSCMSTIP,'') AS SSUBSCMSTIP , NVL(B.SMODELNAME,'') AS SMODELNAME , NVL(B.SGATEWAYIP, SPLIT_PART(A.SLAST_ADDR, '.', 1) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 2) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 3) || '.' || TO_NUMBER(SPLIT_PART(A.SLAST_ADDR, '.', 4)) -2) AS SGATEWAYIP , NVL(B.SSUBSCNESCODE,'') AS SSUBSCNESCODE , NVL(B.SSUBSCNEALIAS,'') AS SSUBSCNEALIAS , NVL(B.SLLNUM,'') AS SLLNUM , NVL(B.SSUBSCLGIPPORTDESCRIPTION,'') AS SSUBSCLGIPPORTDESCRIPTION , NVL(B.SSUBSCLGIPPORTIP,'') AS SSUBSCLGIPPORTIP , NVL(B.SSUBSCROUTERSERIALIP,'') AS SSUBSCROUTERSERIALIP , NVL(B.SCONNALIAS,'') AS SCONNALIAS , NVL(A.SCOMMENT, '') AS SCOMMENT FROM MST.TB_IP_ASSIGN_MST_BAK_20230224 A LEFT OUTER JOIN MST.TB_IP_ALLOC_MST_BAK_20230224 B ON B.NIP_ASSIGN_MST_SEQ = A.NIP_ASSIGN_MST_SEQ INNER JOIN MST.TB_MIG_MOBILE_PIP_PREFIX_RANGE C ON C.PIP_PREFIX = A.PIP_PREFIX AND C.NLVL_MST_SEQ = (CASE WHEN A.NLVL_MST_SEQ = 20316 THEN 20319 WHEN A.NLVL_MST_SEQ = 20306 THEN 20309 WHEN A.NLVL_MST_SEQ = 20313 THEN 20452 WHEN A.NLVL_MST_SEQ = 20404 THEN 20449 ELSE A.NLVL_MST_SEQ END) WHERE A.SIP_CREATE_TYPE_CD = 'CT0005' AND A.SSVC_LINE_TYPE_CD = 'CL0003' AND (CASE WHEN A.NLVL_MST_SEQ = 20316 THEN 20319 WHEN A.NLVL_MST_SEQ = 20306 THEN 20309 WHEN A.NLVL_MST_SEQ = 20313 THEN 20452 WHEN A.NLVL_MST_SEQ = 20404 THEN 20449 ELSE A.NLVL_MST_SEQ END) = #{nlvlMstSeq, jdbcType=BIGINT} AND A.SASSIGN_LEVEL_CD IN ('IA0006', 'IA0005')
GROUP BY A.SSVC_LINE_TYPE_CD , A.SIP_CREATE_TYPE_CD , A.SASSIGN_TYPE_CD , A.PIP_PREFIX , C.PIP_PREFIX_RANGE , NVL(B.SICISOFFICESCODE,'') , NVL(B.SSUBSCMSTIP,'') , NVL(B.SMODELNAME,'') , NVL(B.SGATEWAYIP, SPLIT_PART(A.SLAST_ADDR, '.', 1) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 2) || '.' || SPLIT_PART(A.SLAST_ADDR, '.', 3) || '.' || TO_NUMBER(SPLIT_PART(A.SLAST_ADDR, '.', 4)) -2) , NVL(B.SSUBSCNESCODE,'') , NVL(B.SSUBSCNEALIAS,'') , NVL(B.SLLNUM,'') , NVL(B.SSUBSCLGIPPORTDESCRIPTION,'') , NVL(B.SSUBSCLGIPPORTIP,'') , NVL(B.SSUBSCROUTERSERIALIP,'') , NVL(B.SCONNALIAS,'') , NVL(A.SCOMMENT, '')
) A WHERE A.PIP_PREFIX_RANGE = #{pipprefixRange, jdbcType=VARCHAR} ORDER BY A.PIP_PREFIX
